class ControlledRepository : SearchRepository {
    data class Pending(
        val query: String,
        val result: CompletableDeferred<List<Job>>
    )

    val pending = mutableListOf<Pending>()

    override suspend fun search(query: String): List<Job> {
        val request = Pending(query, CompletableDeferred())
        pending += request
        return request.result.await()
    }
}

