@Test
fun `state changes from idle to content`() = runTest {
    val states = mutableListOf<SearchUiState>()
    val job = backgroundScope.launch(UnconfinedTestDispatcher(testScheduler)) {
        viewModel.uiState.toList(states)
    }

    viewModel.search("kotlin")
    repository.complete(Result.success(listOf(Job("Android"))))
    advanceUntilIdle()

    assertEquals(SearchUiState.Idle, states.first())
    assertTrue(states.last() is SearchUiState.Content)

    job.cancel()
}

