@Test
fun `late ack does not duplicate timed out message`() = runTest {
    val gateway = ControlledChatGateway()
    val vm = ChatViewModel(gateway, dispatcher = StandardTestDispatcher(testScheduler))

    vm.send("hello")
    val clientId = vm.uiState.value.messages.single().clientId

    advanceTimeBy(10_000)
    runCurrent()
    assertEquals(SendStatus.Failed, vm.message(clientId).status)

    gateway.ack(clientId, serverId = "s-1")
    advanceUntilIdle()

    val matches = vm.uiState.value.messages.filter {
        it.clientId == clientId || it.serverId == "s-1"
    }
    assertEquals(1, matches.size)
}

@Test
fun `upstream stops after timeout`() = runTest {
    val source = CountingSource()
    val state = source.flow.stateIn(
        scope = backgroundScope,
        started = SharingStarted.WhileSubscribed(5_000),
        initialValue = 0
    )

    val job = backgroundScope.launch(
        UnconfinedTestDispatcher(testScheduler)
    ) { state.collect() }

    runCurrent()
    assertEquals(1, source.starts)

    job.cancel()
    advanceTimeBy(4_999)
    assertEquals(0, source.stops)

    advanceTimeBy(1)
    runCurrent()
    assertEquals(1, source.stops)
}

