class FakeUserRepository : UserRepository {
    private val events = MutableSharedFlow<UserResult>()
    override fun observeUser(): Flow<UserResult> = events
    suspend fun emit(value: UserResult) = events.emit(value)
}

@Test
fun `old result cannot overwrite latest state`() = runTest {
    viewModel.search("android")
    viewModel.search("kotlin")

    fake.complete("kotlin", listOf(Job("Kotlin")))
    fake.complete("android", listOf(Job("Android")))
    advanceUntilIdle()

    assertEquals("kotlin", viewModel.uiState.value.query)
    assertEquals(listOf("Kotlin"), viewModel.uiState.value.items.map { it.title })
}

@Test
fun logout_cancels_retry_backoff() = runTest {
    viewModel.load()
    advanceTimeBy(1_500)

    viewModel.logout()
    advanceUntilIdle()

    assertEquals(2, api.attempts)
    assertEquals(SessionState.LoggedOut, viewModel.state.value.session)
}
